mapper.select:
/* 사용자 ID 중복 여부 조회 */
SELECT COUNT(*)
FROM TB_USER
WHERE USER_ID = #{userId}

/* 사용자 이메일 중복 여부 조회 */
SELECT COUNT(*)
FROM TB_USER
WHERE EMAIL = #{email}

/* 사용자 수정 시 이메일 중복 여부 조회 */
SELECT COUNT(*)
FROM TB_USER
WHERE EMAIL = #{email}
  AND USER_ID != #{userId}

mapper.insert:
/* 사용자 정보 생성 */
INSERT INTO TB_USER (
    USER_ID
  , USER_NM
  , EMAIL
  , PASSWD
  , PHONE
  , ORG_ID
  , USE_YN
  , LOGIN_FAIL_CNT
  , TWO_FA_YN
  , ACCT_STATUS_CD
  , CREATE_DT
  , MODIFY_DT
  , CRTR_ID
  , MDFR_ID
) VALUES (
    #{userId}
  , #{userNm}
  , #{email}
  , #{passwd}
  , #{phone}
  , #{orgId}
  , 'Y'
  , 0
  , 'N'
  , '001'
  , NOW()
  , NULL
  , #{crtrId}
  , NULL
)

mapper.update:
/* 사용자 정보 수정 */
UPDATE TB_USER
SET
    USER_NM = #{userNm},
    ORG_ID = #{orgId},
    EMAIL = #{email},
    PHONE = #{phone},
    MODIFY_DT = NOW(),
    MDFR_ID = #{mdfrId}
WHERE USER_ID = #{userId}

/* 사용자 정보 논리 삭제 */
UPDATE TB_USER
SET
    USE_YN = 'N',
    ACCT_STATUS_CD = '002'
WHERE USER_ID = #{userId}

/* 사용자 정보 복구 */
UPDATE TB_USER
SET
    USE_YN = 'Y',
    ACCT_STATUS_CD = '001'
WHERE USER_ID = #{userId}

/* 사용자 비밀번호 초기화 */
UPDATE TB_USER
SET
    PASSWD = #{passwd}
    , PWD_CHG_DT = NOW()
    , LOGIN_FAIL_CNT = 0
    , ACCT_STATUS_CD = '001'
    , LOCK_DT = NULL
    , USE_YN = 'Y'
WHERE USER_ID = #{userId}
